import re

def count_politicians(articles, politician_names):
    # Create a set of lowercase politician names for case-insensitive matching
    lowercase_politicians = {name.lower() for name in politician_names}

    # Initialize a dictionary to store counts
    counts = {}

    # Process each article
    for article in articles:
        # Use regex to find all names in the article (case-insensitive and ignore punctuation)
        matches = re.findall(r'\b(?:\w+|\w+[\w-]+)\b', article.lower())
        for name in matches:
            if name in lowercase_politicians:
                counts[name] = counts.get(name, 0) + 1

    return counts
